using REslava.ResultFlow.Generators.ResultFlow;
using System.Collections.Immutable;
using System.Linq;

namespace REslava.ResultFlow.Tests;

/// <summary>
/// Tests for the <c>{MethodName}_Traced</c> extension generated by REslava.ResultFlow (syntax-only).
/// Verifies parity with REslava.Result.Flow: same try/finally wrapper, same observer API calls,
/// but emitted in the user's own namespace using as-written type names.
/// </summary>
[TestClass]
public class TracedExtensionTests
{
    // ── Basic emission ────────────────────────────────────────────────────────

    [TestMethod]
    public void TracedExtension_EmittedForNonStaticResultFlowMethod()
    {
        var source = CreateTypedSource("OrderService", "PlaceOrder",
            "Result<Order>.Ok(new Order()).Bind(o => Result<Order>.Ok(o))");

        var output = RunGenerator(source);

        Assert.IsTrue(output.Contains("public FlowProxy Flow =>"),
            "Generator should emit FlowProxy Flow property for instance class");
        Assert.IsTrue(output.Contains("public sealed class FlowProxy"),
            "Generator should emit FlowProxy sealed class");
    }

    [TestMethod]
    public void TracedExtension_ContainsBeginPipelineCall()
    {
        var source = CreateTypedSource("OrderService", "PlaceOrder",
            "Result<Order>.Ok(new Order()).Bind(o => Result<Order>.Ok(o))");

        var output = RunGenerator(source);

        Assert.IsTrue(output.Contains("global::REslava.Result.PipelineObserver.BeginPipeline("),
            "Generated wrapper should call PipelineObserver.BeginPipeline via global:: alias");
        Assert.IsTrue(output.Contains("\"PlaceOrder\""),
            "BeginPipeline call should pass the method name");
    }

    [TestMethod]
    public void TracedExtension_ContainsNodeIdsStaticField()
    {
        var source = CreateTypedSource("OrderService", "PlaceOrder",
            "Result<Order>.Ok(new Order()).Bind(o => Result<Order>.Ok(o))");

        var output = RunGenerator(source);

        Assert.IsTrue(output.Contains("_nodeIds_PlaceOrder"),
            "Generator should emit _nodeIds_PlaceOrder static field");
        Assert.IsTrue(output.Contains("new string[]"),
            "_nodeIds_ should be a string array");
    }

    [TestMethod]
    public void TracedExtension_ContainsTryFinallyWithDispose()
    {
        var source = CreateTypedSource("OrderService", "PlaceOrder",
            "Result<Order>.Ok(new Order()).Bind(o => Result<Order>.Ok(o))");

        var output = RunGenerator(source);

        Assert.IsTrue(output.Contains("try"),
            "Generated wrapper should have a try block");
        Assert.IsTrue(output.Contains("finally"),
            "Generated wrapper should have a finally block");
        Assert.IsTrue(output.Contains("scope.Dispose()"),
            "finally block should call scope.Dispose()");
    }

    [TestMethod]
    public void TracedExtension_ScopeEndCalledWithResultValues()
    {
        var source = CreateTypedSource("OrderService", "PlaceOrder",
            "Result<Order>.Ok(new Order()).Bind(o => Result<Order>.Ok(o))");

        var output = RunGenerator(source);

        Assert.IsTrue(output.Contains("scope.End("),
            "Generated wrapper should call scope.End");
        Assert.IsTrue(output.Contains("result.IsSuccess"),
            "scope.End should pass result.IsSuccess");
    }

    [TestMethod]
    public void TracedExtension_ReturnValuePassedThrough()
    {
        var source = CreateTypedSource("OrderService", "PlaceOrder",
            "Result<Order>.Ok(new Order()).Bind(o => Result<Order>.Ok(o))");

        var output = RunGenerator(source);

        Assert.IsTrue(output.Contains("return result;"),
            "Generated wrapper should return the result from the real method");
    }

    // ── User namespace (key difference from REslava.Result.Flow) ─────────────

    [TestMethod]
    public void TracedExtension_EmittedInUserNamespace_NotGeneratedResultFlow()
    {
        var source = CreateTypedSource("OrderService", "PlaceOrder",
            "Result<Order>.Ok(new Order()).Bind(o => Result<Order>.Ok(o))");

        var output = RunGenerator(source);

        // REslava.ResultFlow emits FlowProxy partial class in the user's namespace
        Assert.IsTrue(output.Contains("namespace TestNS"),
            "FlowProxy partial class should be emitted in the user's namespace (TestNS)");
    }

    [TestMethod]
    public void TracedExtension_UsesShortTypeName_NotFqn()
    {
        var source = CreateTypedSource("OrderService", "PlaceOrder",
            "Result<Order>.Ok(new Order()).Bind(o => Result<Order>.Ok(o))");

        var output = RunGenerator(source);

        // Syntax-only package uses the as-written type name, not global:: FQN
        // The _self field should be "private readonly OrderService _self", not a global:: FQN
        Assert.IsTrue(output.Contains("private readonly OrderService _self"),
            "REslava.ResultFlow should use short type name (OrderService) for _self field, not FQN");
    }

    // ── Static method exclusion ───────────────────────────────────────────────

    [TestMethod]
    public void TracedExtension_NotEmittedForStaticMethod()
    {
        var source = $@"
using System;

namespace TestNS
{{
    public class Order {{ }}
    public class Result<T>
    {{
        public static Result<T> Ok(T value) => new Result<T>();
        public Result<TOut> Bind<TOut>(Func<T, Result<TOut>> f) => new Result<TOut>();
    }}
    public class OrderService
    {{
        [ResultFlow]
        public static Result<Order> StaticPipeline() =>
            Result<Order>.Ok(new Order()).Bind(o => Result<Order>.Ok(o));
    }}
}}";

        var output = RunGenerator(source);

        Assert.IsFalse(output.Contains("StaticPipeline_Traced"),
            "Generator should NOT emit _Traced for static methods");
    }

    // ── Method with parameters ────────────────────────────────────────────────

    [TestMethod]
    public void TracedExtension_MethodWithParameter_ForwardsToRealMethod()
    {
        var source = $@"
using System;

namespace TestNS
{{
    public class CreateOrderRequest {{ }}
    public class Order {{ }}
    public class Result<T>
    {{
        public static Result<T> Ok(T value) => new Result<T>();
        public Result<TOut> Bind<TOut>(Func<T, Result<TOut>> f) => new Result<TOut>();
    }}
    public partial class OrderService
    {{
        [ResultFlow]
        public Result<Order> PlaceOrder(CreateOrderRequest request) =>
            Result<Order>.Ok(new Order()).Bind(o => Result<Order>.Ok(o));
    }}
}}";

        var output = RunGenerator(source);

        Assert.IsTrue(output.Contains("public FlowProxy Flow =>"),
            "Generator should emit FlowProxy Flow property for method with parameters");
        Assert.IsTrue(output.Contains("_self.PlaceOrder("),
            "Generated FlowProxy should forward to _self.PlaceOrder(...)");
    }

    // ── Two methods on same class ─────────────────────────────────────────────

    [TestMethod]
    public void TracedExtension_TwoMethodsSameClass_BothEmitted()
    {
        var source = $@"
using System;

namespace TestNS
{{
    public class Order {{ }}
    public class Invoice {{ }}
    public class Result<T>
    {{
        public static Result<T> Ok(T value) => new Result<T>();
        public Result<TOut> Bind<TOut>(Func<T, Result<TOut>> f) => new Result<TOut>();
    }}
    public partial class OrderService
    {{
        [ResultFlow]
        public Result<Order> PlaceOrder() =>
            Result<Order>.Ok(new Order()).Bind(o => Result<Order>.Ok(o));

        [ResultFlow]
        public Result<Invoice> CreateInvoice() =>
            Result<Invoice>.Ok(new Invoice()).Bind(i => Result<Invoice>.Ok(i));
    }}
}}";

        var output = RunGenerator(source);

        Assert.IsTrue(output.Contains("_self.PlaceOrder("),
            "First method should have FlowProxy wrapper calling _self.PlaceOrder");
        Assert.IsTrue(output.Contains("_self.CreateInvoice("),
            "Second method should have FlowProxy wrapper calling _self.CreateInvoice");
        Assert.IsTrue(output.Contains("_nodeIds_PlaceOrder"),
            "First method should have _nodeIds_ field");
        Assert.IsTrue(output.Contains("_nodeIds_CreateInvoice"),
            "Second method should have _nodeIds_ field");
    }

    // ── self receiver ─────────────────────────────────────────────────────────

    [TestMethod]
    public void TracedExtension_UsesThisSelfReceiver()
    {
        var source = CreateTypedSource("OrderService", "PlaceOrder",
            "Result<Order>.Ok(new Order()).Bind(o => Result<Order>.Ok(o))");

        var output = RunGenerator(source);

        Assert.IsTrue(output.Contains("_self.PlaceOrder("),
            "Generated FlowProxy should call _self.PlaceOrder(...)");
    }

    // ── Fix #1: Static class emits diagram constant, no _Traced ─────────────

    [TestMethod]
    public void StaticClass_WithResultFlowMethod_EmitsDiagramConstant()
    {
        var source = $@"
using System;

namespace TestNS
{{
    public class Order {{ }}
    public class Result<T>
    {{
        public bool IsSuccess {{ get; }}
        public bool IsFailure {{ get; }}
        public T? Value {{ get; }}
        public static Result<T> Ok(T value) => new Result<T>();
        public static Result<T> Fail(string msg) => new Result<T>();
        public Result<TOut> Bind<TOut>(Func<T, Result<TOut>> f) => new Result<TOut>();
    }}
    public static class OrderService
    {{
        [ResultFlow]
        public static Result<Order> Process() =>
            Result<Order>.Ok(new Order()).Bind(o => Result<Order>.Ok(o));
    }}
}}";

        var output = RunGenerator(source);

        Assert.IsTrue(output.Contains("public const string Process"),
            "Static class should have its diagram constant emitted");
    }

    [TestMethod]
    public void StaticClass_WithResultFlowMethod_DoesNotEmitTracedExtension()
    {
        var source = $@"
using System;

namespace TestNS
{{
    public class Order {{ }}
    public class Result<T>
    {{
        public bool IsSuccess {{ get; }}
        public bool IsFailure {{ get; }}
        public T? Value {{ get; }}
        public static Result<T> Ok(T value) => new Result<T>();
        public static Result<T> Fail(string msg) => new Result<T>();
        public Result<TOut> Bind<TOut>(Func<T, Result<TOut>> f) => new Result<TOut>();
    }}
    public static class OrderService
    {{
        [ResultFlow]
        public static Result<Order> Process() =>
            Result<Order>.Ok(new Order()).Bind(o => Result<Order>.Ok(o));
    }}
}}";

        var output = RunGenerator(source);

        Assert.IsFalse(output.Contains("_Traced_Extensions"),
            "Static class should NOT emit _Traced_Extensions");
        Assert.IsFalse(output.Contains("Process_Traced"),
            "Static class should NOT emit Process_Traced");
    }

    // ── Fix #2: Value-type T uses non-nullable ToString ───────────────────────

    [TestMethod]
    public void TracedExtension_ValueTypeT_UsesNonNullableToString()
    {
        var source = $@"
using System;

namespace TestNS
{{
    public class Result<T>
    {{
        public bool IsSuccess {{ get; }}
        public bool IsFailure {{ get; }}
        public T? Value {{ get; }}
        public static Result<T> Ok(T value) => new Result<T>();
        public static Result<T> Fail(string msg) => new Result<T>();
        public Result<TOut> Bind<TOut>(Func<T, Result<TOut>> f) => new Result<TOut>();
    }}
    public partial class OrderService
    {{
        [ResultFlow]
        public Result<int> PlaceOrder() =>
            Result<int>.Ok(1).Bind(n => Result<int>.Ok(n));
    }}
}}";

        var output = RunGenerator(source);

        Assert.IsTrue(output.Contains("result.Value.ToString()"),
            "Value-type T should emit result.Value.ToString() (non-nullable)");
        Assert.IsFalse(output.Contains("result.Value?.ToString()"),
            "Value-type T should NOT emit result.Value?.ToString()");
    }

    [TestMethod]
    public void TracedExtension_ReferenceTypeT_UsesNullableToString()
    {
        var source = CreateTypedSource("OrderService", "PlaceOrder",
            "Result<Order>.Ok(new Order()).Bind(o => Result<Order>.Ok(o))");

        var output = RunGenerator(source);

        Assert.IsTrue(output.Contains("result.Value?.ToString()"),
            "Reference-type T should emit result.Value?.ToString() (nullable)");
    }

    // ── Helpers ───────────────────────────────────────────────────────────────

    private static string CreateTypedSource(string className, string methodName, string returnExpression) => $@"
using System;

namespace TestNS
{{
    public class Order {{ }}

    public class Result<T>
    {{
        public bool IsSuccess {{ get; }}
        public bool IsFailure {{ get; }}
        public T? Value {{ get; }}
        public System.Collections.Generic.List<object> Errors => new();
        public static Result<T> Ok(T value) => new Result<T>();
        public static Result<T> Fail(string msg) => new Result<T>();
        public Result<TOut> Bind<TOut>(Func<T, Result<TOut>> f) => new Result<TOut>();
        public Result<TOut> Map<TOut>(Func<T, TOut> f) => new Result<TOut>();
        public Result<T> Tap(Action<T> a) => this;
    }}

    public partial class {className}
    {{
        [ResultFlow]
        public Result<Order> {methodName}() => {returnExpression};
    }}
}}";

    private static string RunGenerator(string source)
    {
        var syntaxTree = CSharpSyntaxTree.ParseText(SourceText.From(source));

        var references = new System.Collections.Generic.List<MetadataReference>
        {
            MetadataReference.CreateFromFile(typeof(object).Assembly.Location),
            MetadataReference.CreateFromFile(typeof(Enumerable).Assembly.Location),
        };

        var compilation = CSharpCompilation.Create(
            "TracedExtensionSyntaxTestCompilation",
            new[] { syntaxTree },
            references,
            new CSharpCompilationOptions(OutputKind.DynamicallyLinkedLibrary));

        var generator = new ResultFlowGenerator();
        var driver = CSharpGeneratorDriver.Create(generator);
        var updatedDriver = driver.RunGeneratorsAndUpdateCompilation(compilation, out _, out _);

        var sb = new System.Text.StringBuilder();
        foreach (var tree in updatedDriver.GetRunResult().GeneratedTrees)
        {
            using var writer = new System.IO.StringWriter();
            tree.GetText().Write(writer);
            sb.AppendLine(writer.ToString());
        }
        return sb.ToString();
    }
}
